const ImageWithFallback: React.FC<{ 
  src: string; 
  alt: string; 
  className?: string; 
  fallbackText?: string;
  size?: number;
}> = ({ src, alt, className, fallbackText, size = 16 }) => {
  const [error, setError] = useState(false);
  if (error || !src) {
    return (
      <div className={`${className} bg-slate-100 flex items-center justify-center text-slate-400 border border-slate-200 overflow-hidden`}>
        {fallbackText ? (
          <span className="font-bold text-xs">{fallbackText.substring(0, 1).toUpperCase()}</span>
        ) : (
          <UserCheck size={size} />
        )}
      </div>
    );
  }
  return <img src={src} alt={alt} className={className} onError={() => setError(true)} />;
};

interface ClientDetailProps {
  client: ClientProfile;
  onNavigateToApp: (appId: string) => void;
}

export const ClientDetail: React.FC<ClientDetailProps> = ({ client, onNavigateToApp }) => {
  const [insight, setInsight] = useState<InsightResponse | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);
  const [selectedMaker, setSelectedMaker] = useState<DecisionMaker | null>(null);

  const handleGenerateInsight = async () => {
    setLoadingInsight(true);
    try {
      const data = await generateClientInsight(client);
      setInsight(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingInsight(false);
    }
  };

  const renderSectionHeader = (title: string, icon: React.ReactNode) => (
    <div className="flex items-center gap-3 border-b border-slate-100 pb-4 mb-6">
      <div className="text-slate-900 bg-slate-100 p-1.5 rounded">{icon}</div>
      <div>
        <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">{title}</h3>
      </div>
    </div>
  );

  const teamTree = useMemo(() => {
    const makers = client.decisionTeam;
    const roots = makers.filter(m => !m.reportsTo);

    const buildTree = (parent: DecisionMaker): any => ({
      ...parent,
      children: makers.filter(m => m.reportsTo === parent.id).map(buildTree)
    });

    return roots.map(buildTree);
  }, [client.decisionTeam]);

  // 计算多维预算指标与同比
  const budgetMetrics = useMemo(() => {
    const history = client.annualSpendHistory;

    // 1. 年度总预测消耗：已发生的取实际值，未发生的取预测值
    const totalProjectedSpend = history.reduce((acc, m) => acc + (m.actual ?? m.forecast ?? 0), 0);

    // 2. 上年同期累计消耗 (To Date)
    // 找到当前月份索引（即最后一个有 actual 的月份）
    const lastActualIdx = history.reduce((maxIdx, m, idx) => m.actual !== undefined ? idx : maxIdx, -1);
    const totalLastYearSpendToDate = history.slice(0, lastActualIdx + 1).reduce((acc, m) => acc + m.lastYearActual, 0);

    // 3. 上年全年总消耗
    const totalLastYearSpendFull = history.reduce((acc, m) => acc + m.lastYearActual, 0);

    // 4. 假设上年预算为上年全年总消耗的 95% (用于演示同比变化)
    const lastYearBudget = totalLastYearSpendFull * 0.95;
    const lastYearUtilization = (totalLastYearSpendToDate / lastYearBudget) * 100;
    const currentUtilization = (client.financials.annualSpend / client.financials.annualBudget) * 100;

    // 计算变化率
    const calcRate = (curr: number, prev: number) => prev === 0 ? 0 : ((curr - prev) / prev) * 100;

    return {
      totalProjectedSpend,
      totalLastYearSpendFull,
      budgetYoY: calcRate(client.financials.annualBudget, lastYearBudget),
      spendYoY: calcRate(client.financials.annualSpend, totalLastYearSpendToDate),
      utilizationDiff: currentUtilization - lastYearUtilization,
      projectionYoY: calcRate(totalProjectedSpend, totalLastYearSpendFull)
    };
  }, [client.annualSpendHistory, client.financials]);

  const renderComparison = (val: number, isPercentagePoint: boolean = false) => {
    const isPositive = val > 0;
    const isZero = Math.abs(val) < 0.01;
    if (isZero) return <span className="flex items-center gap-0.5 text-slate-400 font-black"><Minus size={10}/> 0%</span>;

    return (
      <span className={`flex items-center gap-0.5 font-black ${isPositive ? 'text-emerald-600' : 'text-rose-600'}`}>
        {isPositive ? <TrendingUp size={10}/> : <TrendingDown size={10}/>}
        {Math.abs(val).toFixed(1)}{isPercentagePoint ? 'pts' : '%'}
      </span>
    );
  };

  const MakerNode: React.FC<{ maker: any; level: number }> = ({ maker, level }) => {
    const hasChildren = maker.children && maker.children.length > 0;

    const roleMap: Record<string, string> = {
      DECISION: '决策者',
      INFLUENCER: '影响者',
      EXECUTION: '执行者'
    };

    const roleColors = {
      DECISION: 'border-slate-950 bg-white ring-4 ring-slate-950/5',
      INFLUENCER: 'border-blue-600 bg-white ring-4 ring-blue-600/5',
      EXECUTION: 'border-slate-300 bg-slate-50 ring-0'
    };

    return (
      <div className="flex flex-col items-center relative">
        <div 
          onClick={() => setSelectedMaker(maker)}
          className={`relative z-10 w-64 p-5 rounded-lg border-2 cursor-pointer transition-all hover:shadow-xl hover:-translate-y-1 active:scale-95 ${roleColors[maker.role as keyof typeof roleColors]}`}
        >
          <div className="flex items-center gap-4">
            <div className={`w-12 h-12 rounded-full flex items-center justify-center text-white font-black shadow-inner shrink-0 
              ${maker.role === 'DECISION' ? 'bg-slate-950' : maker.role === 'INFLUENCER' ? 'bg-blue-600' : 'bg-slate-400'}`}>
              {maker.name.substring(0, 1)}
            </div>
            <div className="overflow-hidden">
              <div className="flex items-center gap-2 mb-0.5">
                <span className="text-sm font-black text-slate-900 truncate">{maker.name}</span>
                <span className={`text-[8px] px-1.5 py-0.5 rounded font-black uppercase tracking-tighter text-white
                  ${maker.role === 'DECISION' ? 'bg-slate-950' : maker.role === 'INFLUENCER' ? 'bg-blue-600' : 'bg-slate-400'}`}>
                  {roleMap[maker.role] || maker.role}
                </span>
              </div>
              <div className="text-[10px] font-bold text-slate-500 truncate">{maker.title}</div>
              <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">{maker.department}</div>
            </div>
          </div>
          <div className="absolute -bottom-2 -right-2 bg-slate-900 text-white p-1 rounded-full opacity-0 hover:opacity-100 group-hover:opacity-100 transition-opacity">
            <ExternalLink size={10} />
          </div>
        </div>

        {hasChildren && (
          <div className="flex gap-12 mt-12 relative">
            <div className="absolute -top-12 left-1/2 -translate-x-1/2 w-0.5 h-12 bg-slate-200"></div>
            {maker.children.map((child: any) => (
              <MakerNode key={child.id} maker={child} level={level + 1} />
            ))}
          </div>
        )}
      </div>
    );
  };

  const renderCooperationBadges = (coop: AppInMatrix['cooperation']) => {
    const badges = [];
    if (coop.promotion) badges.push({ label: '推广', color: 'bg-blue-100 text-blue-700' });
    if (coop.preinstall) badges.push({ label: '预装', color: 'bg-indigo-100 text-indigo-700' });
    if (coop.commercial) badges.push({ label: '商业化', color: 'bg-emerald-100 text-emerald-700' });
    if (coop.push) badges.push({ label: 'Push联运', color: 'bg-amber-100 text-amber-700' });

    return (
      <div className="flex flex-wrap gap-1 justify-center">
        {badges.map((b, i) => (
          <span key={i} className={`text-[9px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter ${b.color}`}>
            {b.label}
          </span>
        ))}
        {badges.length === 0 && <span className="text-[9px] font-black text-slate-300">无活跃业务</span>}
      </div>
    );
  };

  return (
    <div className="max-w-7xl mx-auto pb-12 space-y-8 animate-in fade-in duration-300">

      {/* 1. 客户基本信息 */}
      <section className="bg-white rounded border border-slate-200 overflow-hidden shadow-sm">
         <div className="p-8 pb-0 flex flex-col md:flex-row justify-between items-start gap-6 mb-6">
            <div className="flex items-center gap-6">
              <ImageWithFallback src={client.logo} alt={client.name} className="w-20 h-20 rounded border border-slate-100 object-cover shadow-sm" fallbackText={client.name} size={32} />
              <div>
                <div className="flex items-center gap-3">
                  <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tight">{client.name}</h1>
                </div>
                <div className="flex items-center gap-3 text-xs text-slate-500 mt-2 font-bold">
                  <span className="flex items-center gap-1"><Building size={12}/> {client.industry}</span>
                  <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                  <span className="font-mono">编号: {client.id}</span>
                  <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                  <span className={`${client.stage === ClientStage.ACTIVE ? 'text-green-600' : 'text-red-600'}`}>{client.stage === ClientStage.ACTIVE ? '活跃状态' : '风险预警'}</span>
                </div>
              </div>
            </div>
         </div>
         <div className="px-8 pb-8 pt-2 grid grid-cols-1 md:grid-cols-3 gap-6 border-t border-slate-50 mt-4">
             <div className="pt-4">
                <div className="text-[10px] text-slate-400 mb-1 font-black uppercase tracking-widest">公司主体</div>
                <div className="text-sm font-bold text-slate-900 truncate" title={client.corporateEntity}>{client.corporateEntity}</div>
             </div>
             <div className="pt-4">
                <div className="text-[10px] text-slate-400 mb-1 font-black uppercase tracking-widest">账户评级</div>
                <div className="flex items-center gap-1.5 text-amber-600 text-sm font-black uppercase">
                  <Award size={14}/> {client.accountRating}
                </div>
             </div>
             <div className="pt-4">
                <div className="text-[10px] text-slate-400 mb-1 font-black uppercase tracking-widest">年消耗预算</div>
                <div className="text-sm font-mono font-bold text-slate-900">¥{(client.financials.annualBudget/1000000).toFixed(1)}百万</div>
             </div>
         </div>
      </section>

      {/* 2. 决策链条图谱 */}
      <section className="bg-white rounded border border-slate-200 p-8 shadow-sm overflow-hidden">
        {renderSectionHeader("决策链条图谱", <UserCheck size={16}/>)}
        <div className="py-12 flex justify-center overflow-x-auto min-h-[400px]">
          <div className="inline-flex gap-20">
            {teamTree.map((root: any) => (
              <MakerNode key={root.id} maker={root} level={0} />
            ))}
          </div>
        </div>
      </section>

      {/* 3. 客户最新动态 */}
      <section className="bg-white rounded border border-slate-200 p-8 shadow-sm">
        {renderSectionHeader("客户最新动态", <Newspaper size={16}/>)}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
           {client.dynamics.map((item, idx) => (
             <div key={idx} className="relative pl-6 border-l-2 border-slate-100 py-2 hover:border-blue-600 transition-colors">
                <div className={`absolute -left-[9px] top-4 w-4 h-4 rounded-full border-2 bg-white
                   ${item.type === 'FINANCE' ? 'border-green-500' : item.type === 'UPDATE' ? 'border-blue-500' : 'border-slate-300'}`}></div>
                <div className="flex items-center gap-2 mb-2">
                   <span className="text-[10px] font-mono font-black text-slate-400 uppercase">{item.date}</span>
                   <span className={`text-[9px] px-2 py-0.5 rounded font-black uppercase tracking-widest border
                      ${item.type === 'FINANCE' ? 'text-green-600 border-green-200 bg-green-50' : 'text-blue-600 border-blue-200 bg-blue-50'}`}>
                      {item.type === 'FINANCE' ? '财务动态' : item.type === 'UPDATE' ? '版本更新' : '战略变动'}
                   </span>
                </div>
                <h4 className="text-sm font-black text-slate-900 mb-2">{item.title}</h4>
                <p className="text-xs text-slate-500 leading-relaxed font-bold">{item.content}</p>
             </div>
           ))}
        </div>
      </section>

      {/* 4. 历次沟通遗留问题 */}
