interface ClientDetailProps {
  client: ClientProfile;
  onNavigateToApp: (appId: string) => void;
}

export const ClientDetail: React.FC<ClientDetailProps> = ({ client, onNavigateToApp }) => {
  const [insight, setInsight] = useState<InsightResponse | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);
  const [selectedMaker, setSelectedMaker] = useState<DecisionMaker | null>(null);

  const handleGenerateInsight = async () => {
    setLoadingInsight(true);
    try {
      const data = await generateClientInsight(client);
      setInsight(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingInsight(false);
    }
  };

  const renderSectionHeader = (title: string, icon: React.ReactNode) => (
    <div className="flex items-center gap-3 border-b border-slate-100 pb-4 mb-6">
      <div className="text-slate-900 bg-slate-100 p-1.5 rounded">{icon}</div>
      <div>
        <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">{title}</h3>
      </div>
    </div>
  );

  const teamTree = useMemo(() => {
    const makers = client.decisionTeam;
    const roots = makers.filter(m => !m.reportsTo);

    const buildTree = (parent: DecisionMaker): any => ({
      ...parent,
      children: makers.filter(m => m.reportsTo === parent.id).map(buildTree)
    });

    return roots.map(buildTree);
  }, [client.decisionTeam]);

  // 计算多维预算指标与同比
  const budgetMetrics = useMemo(() => {
    const history = client.annualSpendHistory;
    const totalProjectedSpend = history.reduce((acc, m) => acc + (m.actual ?? m.forecast ?? 0), 0);
    const lastActualIdx = history.reduce((maxIdx, m, idx) => m.actual !== undefined ? idx : maxIdx, -1);
    const totalLastYearSpendToDate = history.slice(0, lastActualIdx + 1).reduce((acc, m) => acc + m.lastYearActual, 0);
    const totalLastYearSpendFull = history.reduce((acc, m) => acc + m.lastYearActual, 0);
    const lastYearBudget = totalLastYearSpendFull * 0.95;
    const lastYearUtilization = (totalLastYearSpendToDate / lastYearBudget) * 100;
    const currentUtilization = (client.financials.annualSpend / client.financials.annualBudget) * 100;

    const calcRate = (curr: number, prev: number) => prev === 0 ? 0 : ((curr - prev) / prev) * 100;

    return {
      totalProjectedSpend,
      totalLastYearSpendFull,
      budgetYoY: calcRate(client.financials.annualBudget, lastYearBudget),
      spendYoY: calcRate(client.financials.annualSpend, totalLastYearSpendToDate),
      utilizationDiff: currentUtilization - lastYearUtilization,
      projectionYoY: calcRate(totalProjectedSpend, totalLastYearSpendFull)
    };
  }, [client.annualSpendHistory, client.financials]);

  const renderComparison = (val: number, isPercentagePoint: boolean = false) => {
    const isPositive = val > 0;
    const isZero = Math.abs(val) < 0.01;
    if (isZero) return <span className="flex items-center gap-0.5 text-slate-400 font-black"><Minus size={10}/> 0%</span>;

    return (
      <span className={`flex items-center gap-0.5 font-black ${isPositive ? 'text-emerald-600' : 'text-rose-600'}`}>
        {isPositive ? <TrendingUp size={10}/> : <TrendingDown size={10}/>}
        {Math.abs(val).toFixed(1)}{isPercentagePoint ? 'pts' : '%'}
      </span>
    );
  };

  const renderMetricCell = (metric: MetricValue) => {
    return (
      <div className="flex flex-col items-end shrink-0">
        <span className="font-mono font-bold text-slate-900">
          {metric.current > 0 ? `¥${(metric.current/1000000).toFixed(1)}M` : '-'}
        </span>
        {metric.current > 0 && (
          <div className="text-[9px] mt-0.5">
            {renderComparison(metric.yoy)}
          </div>
        )}
      </div>
    );
  };

  const MakerNode: React.FC<{ maker: any; level: number }> = ({ maker, level }) => {
    const hasChildren = maker.children && maker.children.length > 0;
    const roleMap: Record<string, string> = { DECISION: '决策者', INFLUENCER: '影响者', EXECUTION: '执行者' };
    const roleColors = {
      DECISION: 'border-slate-950 bg-white ring-4 ring-slate-950/5',
      INFLUENCER: 'border-blue-600 bg-white ring-4 ring-blue-600/5',
      EXECUTION: 'border-slate-300 bg-slate-50 ring-0'
    };

    return (
      <div className="flex flex-col items-center relative">
        <div 
          onClick={() => setSelectedMaker(maker)}
          className={`relative z-10 w-64 p-5 rounded-lg border-2 cursor-pointer transition-all hover:shadow-xl hover:-translate-y-1 active:scale-95 ${roleColors[maker.role as keyof typeof roleColors]}`}
        >
          <div className="flex items-center gap-4">
            <div className={`w-12 h-12 rounded-full flex items-center justify-center text-white font-black shadow-inner shrink-0 
              ${maker.role === 'DECISION' ? 'bg-slate-950' : maker.role === 'INFLUENCER' ? 'bg-blue-600' : 'bg-slate-400'}`}>
              {maker.name.substring(0, 1)}
            </div>
            <div className="overflow-hidden">
              <div className="flex items-center gap-2 mb-0.5">
                <span className="text-sm font-black text-slate-900 truncate">{maker.name}</span>
                <span className={`text-[8px] px-1.5 py-0.5 rounded font-black uppercase tracking-tighter text-white
                  ${maker.role === 'DECISION' ? 'bg-slate-950' : maker.role === 'INFLUENCER' ? 'bg-blue-600' : 'bg-slate-400'}`}>
                  {roleMap[maker.role] || maker.role}
                </span>
              </div>
              <div className="text-[10px] font-bold text-slate-500 truncate">{maker.title}</div>
              <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">{maker.department}</div>
            </div>
          </div>
        </div>
        {hasChildren && (
          <div className="flex gap-12 mt-12 relative">
            <div className="absolute -top-12 left-1/2 -translate-x-1/2 w-0.5 h-12 bg-slate-200"></div>
            {maker.children.map((child: any) => (
              <MakerNode key={child.id} maker={child} level={level + 1} />
            ))}
          </div>
        )}
      </div>
    );
  };

  const renderCooperationBadges = (coop: AppInMatrix['cooperation']) => {
    const badges = [];
    if (coop.promotion) badges.push({ label: '推广', color: 'bg-blue-100 text-blue-700' });
    if (coop.preinstall) badges.push({ label: '预装', color: 'bg-indigo-100 text-indigo-700' });
    if (coop.commercial) badges.push({ label: '商业化', color: 'bg-emerald-100 text-emerald-700' });
    if (coop.push) badges.push({ label: 'Push联运', color: 'bg-amber-100 text-amber-700' });

    return (
      <div className="flex flex-wrap gap-1 justify-center max-w-[100px]">
        {badges.map((b, i) => (
          <span key={i} className={`text-[8px] font-black px-1 py-0.5 rounded uppercase tracking-tighter ${b.color}`}>
            {b.label}
          </span>
        ))}
        {badges.length === 0 && <span className="text-[8px] font-black text-slate-300">无活跃业务</span>}
      </div>
    );
  };

  return (
    <div className="max-w-7xl mx-auto pb-12 space-y-8 animate-in fade-in duration-300">

      {/* 1. 客户基本信息 */}
      <section className="bg-white rounded border border-slate-200 overflow-hidden shadow-sm">
         <div className="p-8 pb-0 flex flex-col md:flex-row justify-between items-start gap-6 mb-6">
            <div className="flex items-center gap-6">
              <ImageWithFallback src={client.logo} alt={client.name} className="w-20 h-20 rounded border border-slate-100 object-cover shadow-sm" fallbackText={client.name} size={32} />
              <div>
                <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tight">{client.name}</h1>
                <div className="flex items-center gap-3 text-xs text-slate-500 mt-2 font-bold">
                  <span className="flex items-center gap-1"><Building size={12}/> {client.industry}</span>
                  <span className={`${client.stage === ClientStage.ACTIVE ? 'text-green-600' : 'text-red-600'}`}>{client.stage === ClientStage.ACTIVE ? '活跃状态' : '风险预警'}</span>
                </div>
              </div>
            </div>
         </div>
         <div className="px-8 pb-8 pt-2 grid grid-cols-1 md:grid-cols-3 gap-6 border-t border-slate-50 mt-4">
             <div className="pt-4">
                <div className="text-[10px] text-slate-400 mb-1 font-black uppercase tracking-widest">公司主体</div>
                <div className="text-sm font-bold text-slate-900 truncate">{client.corporateEntity}</div>
             </div>
             <div className="pt-4">
                <div className="text-[10px] text-slate-400 mb-1 font-black uppercase tracking-widest">账户评级</div>
                <div className="flex items-center gap-1.5 text-amber-600 text-sm font-black uppercase"><Award size={14}/> {client.accountRating}</div>
             </div>
             <div className="pt-4">
                <div className="text-[10px] text-slate-400 mb-1 font-black uppercase tracking-widest">年预算额</div>
                <div className="text-sm font-mono font-bold text-slate-900">¥{(client.financials.annualBudget/1000000).toFixed(1)}M</div>
             </div>
         </div>
      </section>

      {/* 2. 决策链条图谱 */}
      <section className="bg-white rounded border border-slate-200 p-8 shadow-sm overflow-hidden">
        {renderSectionHeader("决策链条图谱", <UserCheck size={16}/>)}
        <div className="py-12 flex justify-center overflow-x-auto min-h-[400px]">
          <div className="inline-flex gap-20">
            {teamTree.map((root: any) => (
              <MakerNode key={root.id} maker={root} level={0} />
            ))}
          </div>
        </div>
      </section>

      {/* 3. 客户动态 */}
      <section className="bg-white rounded border border-slate-200 p-8 shadow-sm">
        {renderSectionHeader("客户最新动态", <Newspaper size={16}/>)}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
           {client.dynamics.map((item, idx) => (
             <div key={idx} className="relative pl-6 border-l-2 border-slate-100 py-2 hover:border-blue-600 transition-colors">
                <div className={`absolute -left-[9px] top-4 w-4 h-4 rounded-full border-2 bg-white
                   ${item.type === 'FINANCE' ? 'border-green-500' : item.type === 'UPDATE' ? 'border-blue-500' : 'border-slate-300'}`}></div>
                <div className="flex items-center gap-2 mb-2">
                   <span className="text-[10px] font-mono font-black text-slate-400 uppercase">{item.date}</span>
                   <span className="text-[9px] px-2 py-0.5 rounded font-black uppercase tracking-widest border text-slate-600 bg-slate-50">{item.type}</span>
                </div>
                <h4 className="text-sm font-black text-slate-900 mb-2">{item.title}</h4>
                <p className="text-xs text-slate-500 leading-relaxed font-bold">{item.content}</p>
             </div>
           ))}
        </div>
      </section>

      {/* 4. 年度预算执行 */}
      <section className="bg-white rounded border border-slate-200 p-8 shadow-sm">
        {renderSectionHeader("年度预算执行情况 (YTD)", <Target size={16}/>)}
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 mb-8">
            <div className="p-6 bg-slate-50 rounded border border-slate-100">
                <div className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest">年度预算额</div>
                <div className="text-xl font-black text-slate-900">¥{(client.financials.annualBudget/1000000).toFixed(1)}M</div>
                <div className="mt-2 text-[10px] flex items-center gap-1.5 font-bold uppercase">
                  <span className="text-slate-400">YoY:</span>
                  {renderComparison(budgetMetrics.budgetYoY)}
                </div>
            </div>
            <div className="p-6 bg-slate-50 rounded border border-slate-100">
                <div className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest">累计已消耗</div>
                <div className="text-xl font-black text-blue-600">¥{(client.financials.annualSpend/1000000).toFixed(1)}M</div>
                <div className="mt-2 text-[10px] flex items-center gap-1.5 font-bold uppercase">
                  <span className="text-slate-400">YoY同期:</span>
                  {renderComparison(budgetMetrics.spendYoY)}
                </div>
            </div>
            <div className="p-6 bg-slate-50 rounded border border-slate-100">
                <div className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest">预算执行率</div>
                <div className="text-xl font-black text-slate-900">{((client.financials.annualSpend / client.financials.annualBudget) * 100).toFixed(1)}%</div>
                <div className="mt-2 text-[10px] flex items-center gap-1.5 font-bold uppercase">
                  <span className="text-slate-400">同期差异:</span>
                  {renderComparison(budgetMetrics.utilizationDiff, true)}
                </div>
            </div>
            <div className="p-6 bg-slate-50 rounded border border-slate-100 border-l-4 border-l-blue-600">
                <div className="text-[10px] font-black text-blue-600 uppercase mb-1 tracking-widest">年度预测总额</div>
                <div className="text-xl font-black text-slate-900">¥{(budgetMetrics.totalProjectedSpend / 1000000).toFixed(1)}M</div>
                <div className="mt-2 text-[10px] flex items-center gap-1.5 font-bold uppercase">
                  <span className="text-slate-400">vs 上年全额:</span>
                  {renderComparison(budgetMetrics.projectionYoY)}
                </div>
            </div>
        </div>
        <div className="h-[300px] w-full mt-4">
           <ResponsiveContainer width="100%" height="100%">
              <LineChart data={client.annualSpendHistory}>
                 <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                 <XAxis dataKey="date" tick={{fontSize: 10, fontWeight: 700, fill: '#94a3b8'}} axisLine={false} tickLine={false} />
                 <YAxis tick={{fontSize: 10, fontWeight: 700, fill: '#94a3b8'}} axisLine={false} tickLine={false} tickFormatter={(v) => `¥${(v/1000000).toFixed(1)}M`} />
                 <Tooltip contentStyle={{borderRadius: '8px', border: '1px solid #e2e8f0', boxShadow: 'none', fontSize: '12px', fontWeight: 900}} />
                 <Legend iconType="circle" wrapperStyle={{fontSize: '11px', fontWeight: 900, paddingTop: '30px'}} />
                 <Line type="monotone" dataKey="lastYearActual" name="上年同期" stroke="#94a3b8" strokeWidth={2} strokeDasharray="5 5" dot={false} strokeOpacity={0.4}/>
                 <Line type="monotone" dataKey="actual" name="本年实际" stroke="#1e293b" strokeWidth={4} dot={{r: 4, strokeWidth: 2, fill: '#fff'}} activeDot={{r: 6}} connectNulls/>
                 <Line type="monotone" dataKey="forecast" name="趋势预测" stroke="#2563eb" strokeWidth={2} strokeDasharray="8 5" dot={false}/>
              </LineChart>
           </ResponsiveContainer>
        </div>
      </section>

      {/* 5. APP 产品矩阵 (更新后) */}
      <section className="bg-white rounded border border-slate-200 p-8 shadow-sm">
        {renderSectionHeader("APP 产品矩阵 (YTD 核心指标)", <Layers size={16}/>)}
        <div className="overflow-x-auto">
          <table className="w-full text-xs">
            <thead className="bg-slate-50 text-slate-400 border-b border-slate-200">
              <tr>
                <th className="px-4 py-4 text-left font-black uppercase tracking-widest text-[9px]">应用名称</th>
                <th className="px-4 py-4 text-center font-black uppercase tracking-widest text-[9px]">合作业务</th>
                <th className="px-4 py-4 text-right font-black uppercase tracking-widest text-[9px]">直投消耗 (YoY)</th>
                <th className="px-4 py-4 text-right font-black uppercase tracking-widest text-[9px]">DSP消耗 (YoY)</th>
                <th className="px-4 py-4 text-right font-black uppercase tracking-widest text-[9px]">联运收入 (YoY)</th>
                <th className="px-4 py-4 text-right font-black uppercase tracking-widest text-[9px]">预装收入 (YoY)</th>
                <th className="px-4 py-4 text-right font-black uppercase tracking-widest text-[9px]">铺席收入 (YoY)</th>
                <th className="px-4 py-4 text-center font-black uppercase tracking-widest text-[9px]">预算执行率</th>
                <th className="px-4 py-4 text-right font-black uppercase tracking-widest text-[9px]">操作</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {client.appMatrix.map(app => (
                <tr key={app.id} onClick={() => onNavigateToApp(app.id)} className="hover:bg-slate-50 transition-colors cursor-pointer group">
                  <td className="px-4 py-4 flex items-center gap-3">
                    <div className="w-8 h-8 rounded border border-slate-100 bg-slate-900 flex items-center justify-center text-white text-[9px] font-black shrink-0">APP</div>
                    <div className="overflow-hidden">
                        <div className="font-bold text-slate-900 group-hover:text-blue-600 truncate">{app.name}</div>
                        <div className="text-[8px] text-slate-400 font-mono italic">#{app.id}</div>
                    </div>
                  </td>
                  <td className="px-4 py-4 text-center">
                    {renderCooperationBadges(app.cooperation)}
                  </td>
                  <td className="px-4 py-4 text-right">{renderMetricCell(app.directSpend)}</td>
                  <td className="px-4 py-4 text-right">{renderMetricCell(app.dspSpend)}</td>
                  <td className="px-4 py-4 text-right">{renderMetricCell(app.jointRevenue)}</td>
                  <td className="px-4 py-4 text-right">{renderMetricCell(app.preinstallRevenue)}</td>
                  <td className="px-4 py-4 text-right">{renderMetricCell(app.placementRevenue)}</td>
                  <td className="px-4 py-4 text-center">
                    <div className="flex flex-col items-center gap-1">
                       <span className="text-[10px] font-black text-slate-900">{app.budgetUtilization}%</span>
                       <div className="w-12 h-1 bg-slate-100 rounded-full overflow-hidden">
                          <div className={`h-full ${app.budgetUtilization > 90 ? 'bg-red-500' : 'bg-blue-600'}`} style={{width: `${app.budgetUtilization}%`}}></div>
                       </div>
                    </div>
                  </td>
                  <td className="px-4 py-4 text-right">
                      <button className="text-slate-300 group-hover:text-blue-600 transition-colors"><ArrowRight size={14}/></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      {/* AI 分析浮动按钮 */}
      <button 
        onClick={handleGenerateInsight}
        disabled={loadingInsight}
        className="fixed bottom-10 right-10 bg-slate-950 text-white px-6 py-3 rounded-full font-black text-xs uppercase tracking-widest hover:bg-blue-600 transition-all border border-slate-800 shadow-2xl flex items-center gap-3 z-50"
      >
        {loadingInsight ? <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <BrainCircuit size={18} className="text-white"/>}
        生成 AI 分析报告
      </button>

      {/* AI 报告模态框 */}
      {insight && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-sm" onClick={() => setInsight(null)}></div>
            <div className="bg-white rounded border border-slate-200 w-full max-w-2xl relative overflow-hidden flex flex-col max-h-[90vh] shadow-2xl animate-in zoom-in-95 duration-200">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                    <div className="flex items-center gap-2">
                        <Sparkles className="text-blue-600" size={20}/>
                        <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">AI 深度洞察</h3>
                    </div>
                    <button onClick={() => setInsight(null)} className="p-1 hover:bg-slate-200 rounded text-slate-400"><X size={20}/></button>
                </div>
                <div className="p-8 overflow-y-auto space-y-6">
                    <div className="bg-blue-50/50 p-6 rounded border border-blue-100">
                        <h4 className="text-[10px] font-black text-blue-400 uppercase mb-3 tracking-widest">执行摘要</h4>
                        <p className="text-sm text-slate-900 font-bold">{insight.summary}</p>
                    </div>
                    <div className="space-y-3">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">行动建议</h4>
                        {insight.actionItems.map((item, idx) => (
                            <div key={idx} className="flex gap-4 p-4 border border-slate-100 rounded font-bold text-sm text-slate-700">{item}</div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};
